public class LambdaStreamsE1 {

    public static void main(String[] args) {
        List<Integer> nums = List.of(2, 3, 4, 5);
        int sum = nums.stream()
            .filter(x -> x % 2 == 0)
            .map(x -> x * x)
            .reduce(0, Integer::sum);
        System.out.println(sum);
    }
}

